const previousMode = flow.get('current_mode') || null;
const lastChangeTime = flow.get('last_change_time') || 0;
const currentMode = 'heat_pump';

const MIN_DELAY_MINUTES = 15;
const timeSinceLastChange = (Date.now() - lastChangeTime) / 1000 / 60;

if (previousMode !== currentMode) {
    if (timeSinceLastChange >= MIN_DELAY_MINUTES || previousMode === null) {
        flow.set('current_mode', currentMode);
        flow.set('last_change_time', Date.now());
        node.status({fill:"cyan",shape:"dot",text:`✓ Changement: ${previousMode} → HEAT_PUMP`});
        return msg;
    } else {
        node.status({
            fill:"orange",
            shape:"ring",
            text:`⏳ Trop tôt (${timeSinceLastChange.toFixed(1)}/${MIN_DELAY_MINUTES} min)`
        });
        return null;
    }
}

node.status({fill:"grey",shape:"ring",text:"➔ Déjà en HEAT_PUMP"});
return null;

const v = msg.payload.value !== undefined ? msg.payload.value : msg.payload;
flow.set('wh_ac_ignored', v);
node.status({fill:'blue',shape:'dot',text:`AC ignored: ${v}`});
return msg;

const v = msg.payload.value !== undefined ? msg.payload.value : msg.payload;
flow.set('wh_soc', v);
node.status({fill:'blue',shape:'dot',text:`SOC: ${v}%`});
return msg;

const v = msg.payload.value !== undefined ? msg.payload.value : msg.payload;
flow.set('wh_irradiance', v);
node.status({ fill: 'blue', shape: 'dot', text: `Current: ${v}W/m2`});
return msg;

flow.set('current_mode', null);
flow.set('last_change_time', 0);
flow.set('wh_ac_ignored', null);
flow.set('wh_soc', null);
flow.set('wh_battery_current', null);
flow.set('wh_pv_dc', 0);
flow.set('wh_pv_ac', 0);
flow.set('wh_production', 0);

node.status({fill:'green',shape:'dot',text:'Initialisé'});

// Forcer VACATION au démarrage
msg.payload = {mode: 'vacation', reasons: ['Démarrage']};
return msg;

const DEBOUNCE_MINUTES = 5;     // délai de confirmation pour conditions instables

const acIgnored = flow.get('wh_ac_ignored');
const soc = flow.get('wh_soc');
const irradiance = flow.get('wh_irradiance');
const batteryCurrent = flow.get('wh_battery_current');
const now = Date.now();

// --- Conditions avec debounce ---
// acIgnored condition
const acIgnoredActive = (acIgnored !== null && acIgnored !== undefined && acIgnored === 1);

// soc condition (SOC > 90%)
const socHigh = (soc !== null && soc !== undefined && soc > 90);

// irradiance condition (> 400)
const irradianceHighNow = (irradiance !== null && irradiance !== undefined && irradiance > 400);

if (irradianceHighNow) {
    if (!context.get('irradianceHighStart')) {
        context.set('irradianceHighStart', now);
    }
} else {
    context.set('irradianceHighStart', null);
}
const irradianceHighStart = context.get('irradianceHighStart');
const irradianceHighElapsed = irradianceHighStart ? (now - irradianceHighStart) / 60000 : 0;
const irradianceHigh = irradianceHighNow && (irradianceHighElapsed >= DEBOUNCE_MINUTES);

// battery current condition (courant négatif)
const currentNegativeNow = (batteryCurrent !== null && batteryCurrent !== undefined && batteryCurrent < 0);

if (currentNegativeNow) {
    if (!context.get('currentNegativeStart')) {
        context.set('currentNegativeStart', now);
    }
} else {
    context.set('currentNegativeStart', null);
}
const currentNegativeStart = context.get('currentNegativeStart');
const currentNegativeElapsed = currentNegativeStart ? (now - currentNegativeStart) / 60000 : 0;
const currentNegative = currentNegativeNow && (currentNegativeElapsed >= DEBOUNCE_MINUTES);

// --- Décision ---
// Mode VACATION si: AC ignoré actif OU SOC > 90% OU irradiance > 400 OU courant négatif
// Mode HEAT_PUMP sinon
const vacationMode = acIgnoredActive || socHigh || irradianceHigh || currentNegative;

let reasons = [];
if (acIgnoredActive) reasons.push('AC ignoré actif');
if (socHigh) reasons.push(`SOC ${soc}% > 90%`);
if (irradianceHigh) reasons.push(`Irradiance ${irradiance}W/m² > 400 (${irradianceHighElapsed.toFixed(1)}min)`);
if (currentNegative) reasons.push(`Courant négatif ${batteryCurrent}A (${currentNegativeElapsed.toFixed(1)}min)`);

// Statut détaillé même quand en attente de confirmation
let pending = [];
if (irradianceHighNow && !irradianceHigh) pending.push(`Irradiance ${irradianceHighElapsed.toFixed(1)}/${DEBOUNCE_MINUTES}min`);
if (currentNegativeNow && !currentNegative) pending.push(`Courant négatif ${currentNegativeElapsed.toFixed(1)}/${DEBOUNCE_MINUTES}min`);

msg.payload = {
    mode: vacationMode ? 'vacation' : 'heat_pump',
    temperature: vacationMode ? 45 : 60,
    ac_ignored: acIgnored,
    soc: soc,
    irradiance: irradiance,
    battery_current: batteryCurrent,
    reasons: vacationMode ? reasons : [`SOC ≤ 90%, AC ignoré inactif, Irradiance ≤ 400, Courant ≥ 0`]
};

if (vacationMode) {
    node.status({ fill: 'yellow', shape: 'ring', text: `VACATION (45°C): ${reasons.join(' | ')}` });
    return [null, msg];
} else if (pending.length > 0) {
    node.status({ fill: 'orange', shape: 'ring', text: `⏳ Attente: ${pending.join(' | ')}` });
    return [null, null];
} else {
    node.status({ fill: 'cyan', shape: 'dot', text: `HEAT_PUMP (60°C): SOC ${soc}%, Irradiance ${irradiance}W/m²` });
    return [msg, null];
}

